  const updated = "2026-04-12"; // TODO(michael): wire to PDF mtime when scripts/stamp-resume runs
  return (
    <div className="dossier">
      <DossierHeader
        title="MICHAEL QUINTIN"
        tagline={`Curriculum vitae · last updated ${updated}`}
