@import "../styles/tokens.css";
@import "../styles/reset.css";
@import "../styles/print.css";
@import "../styles/experience.css";

/* ----- keyframes ----- */
@keyframes operator-fade-up {
  from { opacity: 0; transform: translateY(8px); }
  to   { opacity: 1; transform: translateY(0); }
}
@keyframes operator-blink {
  0%, 100% { opacity: 1; }
  50%      { opacity: 0; }
}
@media (prefers-reduced-motion: reduce) {
  @keyframes operator-blink { 0%,100% { opacity: 1; } }
}

.cursor-blink {
  display: inline-block;
  animation: operator-blink 1.6s steps(1, end) infinite;
}

/* ----- palette ----- */
.palette-backdrop {
  position: fixed; inset: 0;
  background: rgba(0,0,0,0.55);
  z-index: var(--z-palette);
  animation: operator-fade-up var(--d-fast) var(--ease);
}
.palette {
  position: fixed;
  top: 14vh; left: 50%;
  transform: translateX(-50%);
  width: min(640px, 92vw);
  background: var(--bg-1);
  border: var(--border-hair);
  border-top: 1px solid var(--accent);
  z-index: calc(var(--z-palette) + 1);
  font-family: var(--font-mono);
  color: var(--fg);
  border-radius: 1px;
  display: flex; flex-direction: column;
  max-height: 70vh;
}
.palette-input-row {
  display: flex; align-items: center; gap: var(--s-3);
  height: 40px; padding: 0 var(--s-4);
}
.palette-chevron { color: var(--accent); }
.palette-input-row input {
  flex: 1; outline: none; caret-color: var(--accent);
  font-family: var(--font-mono); font-size: var(--t-sm-size);
}
.palette-input-row input::placeholder { color: var(--fg-mute); }
.palette-kbd {
  background: var(--bg-2); padding: 2px 6px; font-size: var(--t-xxs-size); color: var(--fg-mute);
}
.palette-divider { height: 1px; background: var(--rule); }
.palette-results { overflow: auto; }
.palette-row {
  display: grid;
  grid-template-columns: 24px 1fr auto;
  align-items: center;
  height: 36px; padding: 0 var(--s-4);
  font-size: var(--t-sm-size); cursor: pointer;
  border-left: 2px solid transparent;
}
.palette-row[data-selected="true"] {
  background: var(--bg-3);
  border-left-color: var(--accent);
}
.palette-glyph { color: var(--accent-dim); }
.palette-title { color: var(--fg); white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
.palette-ctx { color: var(--fg-mute); font-size: var(--t-xs-size); padding-left: var(--s-4); white-space: nowrap; }
.palette-empty { padding: var(--s-4); color: var(--fg-mute); font-size: var(--t-xs-size); }
.palette-footer {
  height: 24px; padding: 0 var(--s-4);
  font-size: var(--t-xxs-size); color: var(--fg-mute);
  display: flex; align-items: center;
}

/* ----- toast (R04: top-right, beneath the ⌘K key-cap) ----- */
.toast {
  position: fixed;
  top: calc(var(--keycap-size) + 24px);
  right: 16px;
  background: var(--bg-2); color: var(--fg); border: var(--border-hair);
  padding: var(--s-2) var(--s-4);
  font-family: var(--font-mono); font-size: var(--t-xs-size);
  z-index: var(--z-toast);
}

/* ----- ⌘K key-cap affordance (R04: replaces status bar's hint) ----- */
.keycap {
  position: fixed;
  top: calc(var(--toprail-h) + 12px);
  right: 16px;
  width: var(--keycap-size); height: var(--keycap-size);
  display: inline-flex; align-items: center; justify-content: center;
  font-family: var(--font-mono);
  font-size: var(--t-xs-size);
  color: var(--fg-mute);
  background: var(--bg-1);
  border: var(--border-hair);
  cursor: pointer;
  z-index: var(--z-toast);
  transition: color var(--d-fast) var(--ease), border-color var(--d-fast) var(--ease);
}
.keycap:hover { color: var(--fg); border-color: var(--fg-mute); }
.keycap:focus-visible { outline: 2px solid var(--accent); outline-offset: 2px; }

/* ----- accordion choreography (R01 + R02) ----- */
.panel { transition: flex-basis var(--d-accordion) var(--ease-accordion); }
.panel.is-animating { will-change: flex-basis; }

/* Body content is always mounted (so layout is settled before width
   animates). Visibility is animation-driven, not transition-driven, so
   the entry repeats on every collapse→expand cycle including first mount. */
.panel-body {
  opacity: 0;
  transform: translateY(6px);
  pointer-events: none;
}
.panel[data-state="expanded"] .panel-body {
  pointer-events: auto;
  animation: operator-panel-in 260ms var(--ease-accordion) 260ms forwards;
}
.panel[data-state="collapsed"] .panel-body,
.panel[data-state="neutral"]   .panel-body {
  animation: operator-panel-out 180ms linear forwards;
}

@keyframes operator-panel-in {
  from { opacity: 0; transform: translateY(6px); }
  to   { opacity: 1; transform: translateY(0); }
}
@keyframes operator-panel-out {
  from { opacity: 1; }
  to   { opacity: 0; }
}

/* R02: spine label fades out IN PLACE when expanded. No travel, no morph. */
.spine-content {
  opacity: 1;
  transition: opacity 180ms linear;
}
.panel[data-state="expanded"] .spine-content {
  opacity: 0;
  pointer-events: none;
}

@media (prefers-reduced-motion: reduce) {
  .panel { transition: none; }
  .panel-body { animation: none; opacity: 1; transform: none; pointer-events: auto; }
  .panel[data-state="collapsed"] .panel-body,
  .panel[data-state="neutral"]   .panel-body { opacity: 0; pointer-events: none; }
  .spine-content { transition: none; }
}

/* ----- accordion mobile (<768px): stack vertically ----- */
@media (max-width: 767px) {
  .accordion {
    flex-direction: column !important;
    height: auto !important;
    min-height: calc(100vh - var(--statusbar-h));
  }
  .accordion .panel {
    width: 100% !important;
    border-right: none !important;
    border-bottom: var(--border-hair);
    flex: 0 0 auto !important;
    flex-direction: column !important;
  }
  .accordion .panel-spine {
    flex-direction: row !important;
    height: 56px !important;
    width: 100% !important;
    justify-content: flex-start !important;
    padding: 0 var(--s-4) !important;
    gap: var(--s-4);
  }
  .accordion .panel .panel-spine span[aria-hidden="true"] {
    writing-mode: horizontal-tb !important;
    transform: none !important;
    white-space: normal;
  }
}

/* ----- generic dossier chrome ----- */
.dossier { padding: var(--s-6) var(--s-7); max-width: 1200px; margin: 0 auto; }
.dossier-header { font-family: var(--font-mono); margin-bottom: var(--s-6); }
.dossier-rule {
  display: flex; align-items: baseline; justify-content: space-between;
  border-bottom: var(--border-hair); padding-bottom: var(--s-2); margin-bottom: var(--s-2);
  color: var(--fg-mute);
}
.dossier-title { color: var(--fg-hi); font-size: var(--t-md-size); }
.dossier-bread { color: var(--fg-dim); font-size: var(--t-xs-size); }
.dossier-sub   { color: var(--fg-dim); font-size: var(--t-sm-size); margin-top: var(--s-2); }

.dossier-grid {
  display: grid;
  grid-template-columns: 280px 1fr;
  gap: var(--s-7);
}
@media (max-width: 1024px) {
  .dossier-grid { grid-template-columns: 1fr; }
}
.metadata-pane { font-family: var(--font-mono); font-size: var(--t-sm-size); color: var(--fg); }
.metadata-pane .row { display: grid; grid-template-columns: 96px 1fr; gap: var(--s-3); padding: 4px 0; }
.metadata-pane .k   { color: var(--fg-mute); text-align: right; text-transform: uppercase; }
.metadata-pane .v   { color: var(--fg); }

.synopsis { font-family: var(--font-sans); font-size: var(--t-md-size); line-height: var(--t-md-lh); color: var(--fg); max-width: var(--measure-prose); }
.synopsis p + p { margin-top: var(--s-4); }

.artifacts { margin-top: var(--s-7); font-family: var(--font-mono); }
.artifacts-h { color: var(--fg-mute); border-bottom: var(--border-hair); padding-bottom: var(--s-2); margin-bottom: var(--s-3); }
.artifacts li { display: grid; grid-template-columns: 120px 1fr 1em; gap: var(--s-3); padding: 2px 0; font-size: var(--t-sm-size); }
.artifacts .k { color: var(--fg-mute); }
.artifacts .l { color: var(--fg); }
.artifacts a:hover { text-decoration: underline; text-decoration-thickness: 1px; text-underline-offset: 3px; }

/* ----- projects table ----- */
.projects-table {
  width: 100%; border-collapse: collapse;
  font-family: var(--font-mono); font-size: var(--t-sm-size);
}
.projects-table th, .projects-table td {
  text-align: left; padding: 0 var(--s-3); height: 40px;
  border-bottom: var(--border-hair);
  white-space: nowrap;
}
.projects-table th {
  color: var(--fg-mute); text-transform: uppercase; font-size: var(--t-xs-size); font-weight: normal;
  cursor: pointer;
}
.projects-table tr[data-row]:hover { background: var(--bg-3); cursor: pointer; }
.projects-table tr[aria-selected="true"] { box-shadow: inset 2px 0 0 var(--accent); }

.pill {
  display: inline-block;
  height: 20px; padding: 0 6px;
  font-family: var(--font-mono); font-size: var(--t-xxs-size);
  text-transform: uppercase; line-height: 20px;
  background: var(--bg-2);
}
.pill-active   { color: var(--accent); }
.pill-draft    { color: var(--fg-dim); }
.pill-shipping { color: var(--ok); }
.pill-shipped  { color: var(--fg-mute); }
.pill-archived { color: var(--fg-mute); background: var(--bg-1); outline: 1px solid var(--rule); }

.projects-table-wrap { display: block; }
.projects-detail { display: none; }
@media (min-width: 1280px) {
  .projects-table-wrap {
    display: grid;
    grid-template-columns: 1fr 320px;
    gap: var(--s-5);
    align-items: start;
  }
  .projects-detail {
    display: block;
    padding: var(--s-4);
    border-left: var(--border-hair);
    position: sticky; top: var(--s-6);
  }
}

/* ----- book page (PRP) ----- */
.pe-book { background: oklch(0.20 0.01 75); }
.pe-prose { font-family: var(--font-serif); font-size: var(--t-md-size); line-height: 1.7; max-width: var(--measure-book); hyphens: auto; }
.pe-prose p + p { margin-top: var(--s-4); }
.pe-prose .first-block::first-letter {
  font-family: var(--font-serif); font-size: 3em;
  float: left; line-height: 0.9; padding-right: 8px; padding-top: 4px;
}
.pe-title-mono { font-family: var(--font-mono); letter-spacing: 0.12em; font-size: var(--t-xs-size); }
---shell---
"use client";
import { type ReactNode } from "react";
import TopRail from "./TopRail";
import HelpModal from "./HelpModal";
import KeyCap from "./KeyCap";
import NavigationLogger from "./NavigationLogger";
import Palette from "@/components/palette/Palette";
import EasterEggs from "@/components/easter/EasterEggs";
import { Analytics } from "@vercel/analytics/next";
import { usePathname } from "next/navigation";

type Props = { children: ReactNode; buildVersion: string };

export default function Shell({ children, buildVersion }: Props) {
  const path = usePathname() ?? "/";
  const isLanding = path === "/";
  return (
    <>
      <a href="#main" className="sr-only" style={{ position: "absolute", top: 0, left: 0 }}>
        Skip to content
      </a>
      <TopRail />
      <main
        id="main"
        role="main"
        style={{
          paddingTop: isLanding ? 0 : "var(--toprail-h)",
          minHeight: "100vh",
          background: "var(--bg-1)",
          color: "var(--fg)",
        }}
      >
        {children}
      </main>
      {/* R04: status bar deleted. Hidden aria-live region replaces its
          screen-reader role for toast announcements. */}
      <div id="operator-aria-live" role="status" aria-live="polite" className="sr-only" />
      <KeyCap />
      <Palette buildVersion={buildVersion} />
      <HelpModal />
      <EasterEggs />
      <NavigationLogger />
      <Analytics />
    </>
  );
}

